using namespace std;
struct zb{
	int x,y;
}a[1002][1002];
int main(void){
	int n,m,x,y,sx,sy,l;
	cin>>m>>n>>sx>>sy;
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++){
			cin>>a[i][j].x>>a[i][j].y;
		}
	}
	while(a[sx][sy].x+a[sx][sy].y){
		cout<<sx<<' '<<sy<<endl;
